	#include <errno.h>
	#include <stdlib.h>

	#include <boost/asio.hpp>

	int main()
	{
		boost::asio::io_service io_service;
		boost::asio::detail::socket_type s = -1;
		{
			boost::asio::ip::tcp::socket sock(io_service);
			s = socket(PF_INET, SOCK_STREAM, IPPROTO_TCP);
			sock.assign(boost::asio::ip::tcp::v4(), s);
		}
		int val;
		int len = sizeof(val);
		return getsockopt(s, SOL_SOCKET, SO_ACCEPTCONN, (char *)&val, &len);
	}

